/* CoreUp local math renderer (V35). Provides a small offline KaTeX-compatible API for the formulas used in STAT102. */
(function(){
  function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;');}
  function normalize(tex){return String(tex==null?'':tex).replace(/\\\\/g,'\\').replace(/\s+/g,' ').trim();}
  function parseGroup(s,i){
    while(i<s.length && /\s/.test(s[i])) i++;
    if(s[i] !== '{') return {body:s[i]||'', end:i+1};
    var depth=0, start=i+1;
    for(var j=i;j<s.length;j++){
      if(s[j]==='{' && s[j-1] !== '\\') depth++;
      if(s[j]==='}' && s[j-1] !== '\\'){
        depth--;
        if(depth===0) return {body:s.slice(start,j), end:j+1};
      }
    }
    return {body:s.slice(start), end:s.length};
  }
  function commandAt(s,i){
    if(s[i] !== '\\') return null;
    if(i+1 < s.length && /[a-zA-Z]/.test(s[i+1])){
      var j=i+1;
      while(j<s.length && /[a-zA-Z]/.test(s[j])) j++;
      return {name:s.slice(i+1,j), end:j};
    }
    return {name:s[i+1]||'', end:i+2};
  }
  function renderExpr(tex){
    var s=normalize(tex).replace(/\\left/g,'').replace(/\\right/g,'').replace(/\\,/g,' ');
    var out='', i=0;
    while(i<s.length){
      if(s[i]==='\\'){
        var cmd=commandAt(s,i);
        if(!cmd){out+=esc(s[i++]); continue;}
        if(cmd.name==='frac' || cmd.name==='dfrac'){
          var g1=parseGroup(s,cmd.end), g2=parseGroup(s,g1.end);
          out+='<span class="cu-mfrac"><span class="cu-num">'+renderExpr(g1.body)+'</span><span class="cu-den">'+renderExpr(g2.body)+'</span></span>';
          i=g2.end; continue;
        }
        var map={phi:'φ',theta:'θ',times:'×',cdots:'⋯',ldots:'…',ln:'ln',lfloor:'⌊',rfloor:'⌋',lceil:'⌈',rceil:'⌉',le:'≤',ge:'≥',approx:'≈',neq:'≠',infty:'∞',sum:'Σ'};
        if(cmd.name==='%' || cmd.name==='%'){out+='%'; i=cmd.end; continue;}
        if(cmd.name==='{' || cmd.name==='}' || cmd.name==='(' || cmd.name===')' || cmd.name==='[' || cmd.name===']') {out+=esc(cmd.name); i=cmd.end; continue;}
        if(map[cmd.name]) {out+='<span class="cu-op">'+map[cmd.name]+'</span>'; i=cmd.end; continue;}
        // Unknown command: show its name cleanly instead of raw slash.
        out+=esc(cmd.name); i=cmd.end; continue;
      }
      if(s[i]==='_' || s[i]==='^'){
        var sup=s[i]==='^', g=parseGroup(s,i+1);
        out+=(sup?'<sup>':'<sub>')+renderExpr(g.body)+(sup?'</sup>':'</sub>');
        i=g.end; continue;
      }
      if(s[i]==='{'){
        var gg=parseGroup(s,i);
        out+=renderExpr(gg.body); i=gg.end; continue;
      }
      if(s[i]==='}') {i++; continue;}
      out+=esc(s[i]); i++;
    }
    return out.replace(/\s+/g,' ');
  }
  function renderToString(tex, options){
    options=options||{};
    var html=renderExpr(tex);
    var cls='katex cu32-mini-math'+(options.displayMode?' cu32-mini-math-display':'');
    return '<span class="'+cls+'" dir="ltr"><span class="katex-html">'+html+'</span></span>';
  }
  function render(tex, element, options){ if(element) element.innerHTML=renderToString(tex, options); }
  function renderText(text){
    var s=normalize(text).replace(/\\bphi_i\\b/g,'\\\\phi_i'), out='', last=0;
    var re=/\\\[([\s\S]*?)\\\]|\\\(([\s\S]*?)\\\)/g, m;
    while((m=re.exec(s))){
      out+=esc(s.slice(last,m.index));
      out+=renderToString(m[1]!=null?m[1]:m[2],{displayMode:m[1]!=null});
      last=re.lastIndex;
    }
    return out+esc(s.slice(last));
  }
  function renderMathInElement(el){
    if(!el) return;
    var walker=document.createTreeWalker(el,NodeFilter.SHOW_TEXT,null);
    var nodes=[], n;
    while((n=walker.nextNode())) if(/\\\(|\\\[/.test(n.nodeValue||'')) nodes.push(n);
    nodes.forEach(function(node){
      var span=document.createElement('span'); span.innerHTML=renderText(node.nodeValue); node.parentNode.replaceChild(span,node);
    });
  }
  window.katex={renderToString:renderToString, render:render, version:'coreup-v35-local'};
  window.renderMathInElement=renderMathInElement;
  window.CoreUpMathRendererV35={normalize:normalize, renderExpr:renderExpr, renderText:renderText};
})();
